import json
from typing import List, Dict
import unittest
import itertools

class AdjacentCoordinateFinder:
    def __init__(self, json_file_location: str = "/Users/kkreth/PycharmProjects/cgan/configs/Umass_experiments.txt"):
        self.json_file_location = json_file_location
        self.data_cache = {}  # Cache to store enumerated values for each key
        self.current_key = None

    def set_key(self, key: str):
        self.current_key = key
        if key not in self.data_cache:
            self.load_data(key)

    def load_data(self, key: str):
        with open(self.json_file_location, 'r') as file:
            json_data = json.load(file)
        if key not in json_data:
            raise ValueError(f"Key {key} not found in JSON file.")

        self.data_cache[key] = {
            'x_enumerated': json_data[key]['x_enumerated'],
            'y_enumerated': json_data[key]['y_enumerated'],
            'z_enumerated': json_data[key]['z_enumerated']
        }

    def locate_adjacent_values(self, value: float, enumerated_list: List[float]) -> List[float]:
        sorted_list = sorted(enumerated_list)
        index = sorted_list.index(value)
        if index < 2 or index >= len(sorted_list) - 2:
            raise ValueError("Coordinate not found")
        return sorted_list[index - 2:index + 3]

    def find_adjacent_coordinates(self, x: float, y: float, z: float) -> List[List[float]]:
        if self.current_key is None or self.current_key not in self.data_cache:
            raise ValueError("Key is not set or data for the key is not loaded.")

        x_values = self.locate_adjacent_values(x, self.data_cache[self.current_key]['x_enumerated'])
        y_values = self.locate_adjacent_values(y, self.data_cache[self.current_key]['y_enumerated'])
        z_values = self.locate_adjacent_values(z, self.data_cache[self.current_key]['z_enumerated'])
        return list(itertools.product(x_values, y_values, z_values))

